async (page) => {
  // Close any open menus first
  await page.evaluate(() => {
    if (window.game && window.game.menu) window.game.menu.hide();
  });
  await page.waitForTimeout(500);

  // Try warp using the warp panel directly
  const result = await page.evaluate(() => {
    try {
      const warp = window.game.menu.warp;
      warp.show();
      return {shown: true, warpKeys: Object.keys(warp).slice(0, 10)};
    } catch(e) { return {error: e.toString()}; }
  });

  await page.waitForTimeout(1000);

  // Click warp0
  await page.evaluate(() => {
    const btn = document.getElementById('warp0');
    if (btn) btn.click();
  });
  await page.waitForTimeout(5000);

  const pos = await page.evaluate(() => window.__latestGameState.player_position);
  return JSON.stringify({warpResult: result, pos});
}

async (page) => {
