async (page) => {
  // Navigate to nearby Oak trees near Mudwich (safe zone)
  const doStep = async (tx, ty) => {
    await page.evaluate(({x, y}) => window.game.player.go(x, y), {x: tx, y: ty});
    await page.waitForTimeout(2500);
    return await page.evaluate(() => window.__latestGameState.player_position);
  };

  // Walk to the oak tree area near (186, 150)
  await doStep(185, 152);

  const getLogs = async () => {
    const s = await page.evaluate(() => window.__latestGameState);
    return (s.inventory || []).filter(i=>i.key==='logs').reduce((a,i)=>a+i.count,0);
  };

  let logs = await getLogs();
  let chops = 0;

  while (logs < 10 && chops < 15) {
    // Get fresh legend
    const legend = await page.evaluate(() => {
      const m = window.__latestAsciiMap;
      return m && !m.error ? m.legendText : '';
    });

    // Find nearest Oak in legend
    const treeMatch = legend.match(/E(\d+) \[[\^]\] Oak .* dist=(\d+)/);
    if (!treeMatch) {
      // No oak on screen, walk around
      await doStep(182, 148);
      chops++;
      continue;
    }

    const label = `E${treeMatch[1]}`;
    await page.evaluate((l) => window.__clickEntity(l), label);
    await page.waitForTimeout(4000);

    // Check HP — if below 50%, flee
    const hp = await page.evaluate(() => {
      const s = window.__latestGameState;
      return {hp: s.player_stats.hp, max_hp: s.player_stats.max_hp};
    });
    if (hp.hp < hp.max_hp * 0.4) {
      // Walk away from danger
      await doStep(188, 162);
      await page.waitForTimeout(15000); // passive regen
    }

    logs = await getLogs();
    chops++;
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({pos: s.player_position, logs: (s.inventory||[]).filter(i=>i.key==='logs').reduce((a,i)=>a+i.count,0), hp: s.player_stats.hp});
  });
  return finalState;
}

