async (page) => {
  const asciiMap = await page.evaluate(() => {
    const m = window.__latestAsciiMap;
    if (!m || m.error) return 'no map';
    const lines = m.ascii.split('\n').slice(0, 25).join('\n');
    const legend = m.legendText ? m.legendText.slice(0, 1200) : '';
    return lines + '\n...\n' + legend;
  });
  return asciiMap;
}
